const duplicates = [1, 2, 2, 3, 1, 4];
const uniqueSet = new Set(duplicates);

console.log(uniqueSet.has(2)); // true
console.log([...uniqueSet]);   // [1, 2, 3, 4]`,exercises:[{id:"set-deduplicate-list",title:"Array Cleaner Deduplicator",difficulty:"Warm-up",conceptContext:"A Set removes duplicate values from an array instantly. We can convert back to an array using the Spread operator: `[...new Set(arr)]`.",description:"Let's warm up with basic Set deduplication.\n\nWrite a function `deduplicateList(arr)` that quickly prunes duplicate values from an array, returning a clean deduplicated array.",codeTemplate:`function deduplicateList(arr) {
