const steps = [1, 2, 3, 6, 7];
const intervals = [];

let start = steps[0];
let prev = steps[0];

for (let i = 1; i < steps.length; i++) {
  if (steps[i] === prev + 1) {
    prev = steps[i];
  } else {
    intervals.push([start, prev]);
    start = steps[i];
    prev = steps[i];
  }
}
